        level_5_symbols.add(item['symbol'])

with open(path_patents, 'r') as f:
    patents = json.load(f)

# Determine matching strategy
sample_symbols = list(level_5_symbols)[:100]
if all(len(s) == 4 for s in sample_symbols):
    match_mode = 'subclass'
